<script setup lang="ts">import {contentRepository} from '~/repositories/dummy/content.repository';import type{ContentItem}from'~/types/content';definePageMeta({layout:'admin',middleware:'admin-auth'});useSeoMeta({title:'Kelola Konten',robots:'noindex, nofollow'});const items=ref<ContentItem[]>([]),search=ref(''),loading=ref(true),notice=ref('');const load=async()=>{loading.value=true;items.value=(await contentRepository.list({search:search.value,perPage:50})).items;loading.value=false};onMounted(load);watch(search,()=>{setTimeout(load,300)});const remove=async(x:ContentItem)=>{if(confirm(`Hapus “${x.title}”?`)){await contentRepository.remove(x.id);notice.value='Konten berhasil dihapus.';await load()}};const add=async()=>{await contentRepository.create({title:'Konten Baru Demo',slug:`konten-baru-${Date.now()}`,excerpt:'Konten demonstrasi baru.',body:'Isi konten demonstrasi.',category:'Berita',status:'draft'});notice.value='Konten draft berhasil ditambahkan.';await load()};const reset=()=>{if(confirm('Reset seluruh dummy data?')){localStorage.removeItem('sdn-sukorame-2-demo-db-v1');notice.value='Dummy data telah direset.';load()}}</script><template><div><div class="flex flex-wrap items-center justify-between gap-3"><div><h1 class="text-3xl font-bold text-school-navy">Kelola Konten</h1><p class="mt-1 text-muted">CRUD demo tersimpan di browser.</p></div><button class="btn btn-primary" @click="add"><Icon name="mdi:plus"/> Tambah Draft</button></div><p v-if="notice" role="status" class="mt-5 rounded-xl bg-green-100 p-3 text-green-900">{{notice}}</p><div class="card mt-6 p-4"><label class="text-sm font-semibold" for="search">Cari konten</label><input id="search" v-model="search" class="mt-2 w-full rounded-xl border border-line p-3" placeholder="Ketik judul..."></div><div class="card mt-5 overflow-x-auto"><div v-if="loading" class="p-8 text-center"><Icon name="mdi:loading" class="animate-spin"/> Memuat...</div><table v-else class="w-full min-w-[720px] text-left"><thead class="bg-slate-50 text-sm"><tr><th class="p-4">Judul</th><th>Kategori</th><th>Status</th><th class="p-4 text-right">Aksi</th></tr></thead><tbody><tr v-for="x in items" :key="x.id" class="border-t border-line"><td class="p-4 font-semibold">{{x.title}}</td><td>{{x.category}}</td><td><span class="rounded-full bg-blue-100 px-3 py-1 text-xs">{{x.status}}</span></td><td class="p-4 text-right"><button class="text-red-700" :aria-label="`Hapus ${x.title}`" @click="remove(x)"><Icon name="mdi:delete-outline" size="22"/></button></td></tr></tbody></table></div><button class="btn btn-secondary mt-5" @click="reset"><Icon name="mdi:restore"/> Reset Dummy Data</button></div></template>
